// ---------- BODY ----------
let body = "";
const payload = $json.payload || {};

// Check for plain text or HTML body
if (payload.body && payload.body.data) {
  body = Buffer.from(payload.body.data, 'base64').toString();
} else if (payload.parts && Array.isArray(payload.parts)) {
  for (const p of payload.parts) {
    if (p.mimeType === 'text/plain' && p.body && p.body.data) {
      body = Buffer.from(p.body.data, 'base64').toString();
      break; 
    }
  }
}

// Fallback to snippet if body is entirely missing
if (!body && $json.snippet) {
  body = $json.snippet;
}

// ---------- DATE ----------
let date_iso = "";
if ($json.internalDate) {
  const ms = Number($json.internalDate);
  const d = new Date(ms);
  if (!isNaN(d)) {
    // Spring Boot expects ISO format (e.g., "2026-02-25T14:30:00")
    // slice(0, 19) removes the milliseconds and 'Z' to match typical LocalDateTime parsing
    date_iso = d.toISOString().slice(0, 19); 
  }
}

// ---------- EMAIL EXTRACTION ----------
const rawFrom = $json.headers?.from || $json.From || "";
// Extract email from "Name <email@domain.com>" using Regex
const emailMatch = rawFrom.match(/<([^>]+)>/);
const cleanEmail = emailMatch ? emailMatch[1] : rawFrom.trim();

const subject = $json.headers?.subject || $input.first().json.Subject || "";

// ---------- RETURN EXACT DTO FORMAT ----------
return [{
  email: cleanEmail,
  subject: subject,
  emailBody: body,
  repliedAt: date_iso
}];
